async (params, browser) => {
  // Open job posting
  await browser.open(`${params.job_url}`)

  // Wait for job page to load
  await browser.waitForSelector('.jobsearch-JobInfoHeader-title, h1.jobsearch-JobInfoHeader-title, [data-testid="jobsearch-JobInfoHeader-title"]', 15000)

  // Let page settle
  await browser.wait(2000)

  // Get job info before saving
  const job_info = await browser.evaluate(`const titleEl = document.querySelector('.jobsearch-JobInfoHeader-title, h1.jobsearch-JobInfoHeader-title, [data-testid="jobsearch-JobInfoHeader-title"]'); const companyEl = document.querySelector('[data-testid="inlineHeader-companyName"] a, .jobsearch-InlineCompanyRating a'); const jobTitle = titleEl ? titleEl.textContent.trim() : 'Unknown'; const company = companyEl ? companyEl.textContent.trim() : ''; return { job_title: jobTitle, company: company }`)

  // Click save/bookmark button
  const save_result = await browser.evaluate(`const saveBtn = document.querySelector('button[aria-label*="Save"], button[aria-label*="save"], button.jobsearch-SaveJobButton, [data-testid="save-job-button"], button.css-1kwnlnx, #saveJobButton, button[id*="save"]'); const alreadySaved = document.querySelector('button[aria-label*="Saved"], button[aria-label*="saved"], button.jobsearch-SaveJobButton.saved, [data-testid="saved-job-button"]'); if (alreadySaved) { return { success: true, already_saved: true, message: 'Job is already saved' }; } if (saveBtn) { saveBtn.click(); return { success: true, already_saved: false, message: 'Save button clicked' }; } const heartBtn = document.querySelector('button[aria-label*="heart"], button[aria-label*="favorite"], .jobsearch-SaveJob button, button svg[aria-label*="save"]'); if (heartBtn) { const btn = heartBtn.closest('button') || heartBtn; btn.click(); return { success: true, already_saved: false, message: 'Save button clicked (heart icon)' }; } return { success: false, already_saved: false, message: 'Save button not found. You may need to be logged in to Indeed.' }`)

  // Wait for save action to complete
  await browser.wait(2000)

  // Confirm save action
  const confirmation = await browser.evaluate(`const savedIndicator = document.querySelector('button[aria-label*="Saved"], button[aria-label*="saved"], button.jobsearch-SaveJobButton.saved, [data-testid="saved-job-button"]'); const loginModal = document.querySelector('#login-modal, .auth-modal, [data-testid="login-modal"], form[action*="login"]'); if (loginModal) { return { confirmed: false, message: 'Login required. Please sign in to Indeed to save jobs.', url: window.location.href }; } return { confirmed: !!savedIndicator, message: savedIndicator ? 'Job saved successfully' : 'Save action completed - verify in your Indeed account', url: window.location.href }`)

  return confirmation
}
